sys_script_include.script:
function HtmlRenderPageQRCodeView()
{
	var GetParam = x_snc_devtools.GetParam;
	var IsValidSysId = x_snc_devtools.IsValidSysId;
	var GetRecord = x_snc_devtools.GetRecord;
	var IsValidRecord = x_snc_devtools.IsValidRecord;
	var GetStringValue = x_snc_devtools.GetStringValue;
	var HtmlRenderError = x_snc_devtools.HtmlRenderError;
	var HtmlRenderQRCode = x_snc_devtools.HtmlRenderQRCode;

	if (IsActive() == false)
	{
		return	HtmlRenderError('QR Code is inactive.');
	}

	var strPayload = GetParam('payload');

	if (strPayload == '')
	{
		var strSysId = GetParam('sys_id',IsValidSysId);
		if (IsValidSysId(strSysId) == true)
		{
			var grQRCode = GetRecord('x_snc_qrcode_qrcode',strSysId);
			if (IsValidRecord(grQRCode) == true)
			{
				strPayload = GetStringValue(grQRCode.payload);
			}
		}
	}

	if (strPayload == '')
	{
		return	HtmlRenderError('No payload specified');
	}

	var strHtml = '';
	strHtml += HtmlRenderQRCode(strPayload,14,'cm');
	return strHtml;
}
